def private?
    case @family
    when Socket::AF_INET
      @addr & 0xff000000 == 0x0a000000 ||    # 10.0.0.0/8
        @addr & 0xfff00000 == 0xac100000 ||  # 172.16.0.0/12
        @addr & 0xffff0000 == 0xc0a80000     # 192.168.0.0/16
    when Socket::AF_INET6
      @addr & 0xfe00_0000_0000_0000_0000_0000_0000_0000 == 0xfc00_0000_0000_0000_0000_0000_0000_0000 ||
        (@addr >> 32 == 0xffff && (
          @addr & 0xff000000 == 0x0a000000 ||  # ::ffff:10.0.0.0/8
          @addr & 0xfff00000 == 0xac100000 ||  # ::ffff:172.16.0.0/12
          @addr & 0xffff0000 == 0xc0a80000     # ::ffff:192.168.0.0/16
        ))
    else
      raise AddressFamilyError, "unsupported address family"
    end
  end

  # Returns true if the ipaddr is a link-local address.  IPv4
  # addresses in 169.254.0.0/16 reserved by RFC 3927 and link-local
  # IPv6 Unicast Addresses in fe80::/10 reserved by RFC 4291 are
  # considered link-local. Link-local IPv4 addresses in the
  # IPv4-mapped IPv6 address range are also considered link-local.

# frozen_string_literal: true
module GraphQL
  module StaticValidation
    class VariablesAreUsedAndDefinedError < StaticValidation::Error
      attr_reader :variable_name
      attr_reader :violation

      VIOLATIONS = {
        :VARIABLE_NOT_USED     => "variableNotUsed",
        :VARIABLE_NOT_DEFINED  => "variableNotDefined",
      }

      def initialize(message, path: nil, nodes: [], name:, error_type:)
        super(message, path: path, nodes: nodes)
        @variable_name = name
        raise("Unexpected error type: #{error_type}") if !VIOLATIONS.values.include?(error_type)
        @violation = error_type
      end

      # A hash representation of this Message
      def to_h
        extensions = {
          "code" => code,
          "variableName" => variable_name
        }

        super.merge({
          "extensions" => extensions
        })
      end

      def code
        @violation
      end
    end
  end
end

# frozen_string_literal: true
module GraphQL
  module StaticValidation
    class VariableDefaultValuesAreCorrectlyTypedError < StaticValidation::Error
      attr_reader :variable_name
      attr_reader :type_name
      attr_reader :violation

      VIOLATIONS = {
        :INVALID_TYPE         => "defaultValueInvalidType",
        :INVALID_ON_NON_NULL  => "defaultValueInvalidOnNonNullVariable",
      }

      def initialize(message, path: nil, nodes: [], name:, type: nil, error_type:)
        super(message, path: path, nodes: nodes)
        @variable_name = name
        @type_name = type
        raise("Unexpected error type: #{error_type}") if !VIOLATIONS.values.include?(error_type)
        @violation = error_type
      end

      # A hash representation of this Message
      def to_h
        extensions = {
          "code" => code,
          "variableName" => variable_name
        }.tap { |h| h["typeName"] = type_name unless type_name.nil? }

        super.merge({
          "extensions" => extensions
        })
      end

      def code
        @violation
      end
    end
  end
end
